#ifndef DMK_AOT_KERNELS_CUDA_HPP
#define DMK_AOT_KERNELS_CUDA_HPP

// Host-includable declarations for the CUDA AOT getters defined in
// src/cuda_kernels.cu (auto-generated by scripts/generate_aot_kernels).
//
// The returned residual_evaluator_func<Real> launches a CUDA kernel; all
// pointer arguments to it must be device-resident.

#include <dmk/types.hpp>

namespace dmk {
template <class Real>
residual_evaluator_func<Real> get_laplace_2d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
template <class Real>
residual_evaluator_func<Real> get_laplace_3d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
template <class Real>
residual_evaluator_func<Real> get_sqrt_laplace_2d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
template <class Real>
residual_evaluator_func<Real> get_sqrt_laplace_3d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
template <class Real>
residual_evaluator_func<Real> get_stokeslet_3d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
template <class Real>
residual_evaluator_func<Real> get_stresslet_3d_kernel_cuda(dmk_eval_type eval_level, int n_digits);
} // namespace dmk

#endif // DMK_AOT_KERNELS_CUDA_HPP
